Worker threads module enables running JavaScript code in parallel threads for CPU-intensive tasks.

**Basic Worker**:
```javascript
// main.js
const { Worker } = require('worker_threads');

function runService(workerData) {
  return new Promise((resolve, reject) => {
    const worker = new Worker('./worker.js', { workerData });
    worker.on('message', resolve);
    worker.on('error', reject);
    worker.on('exit', (code) => {
      if (code !== 0)
        reject(new Error(`Worker stopped with exit code ${code}`));
    });
  });
}

async function main() {
  const result = await runService({ data: 'heavy computation' });
  console.log('Result:', result);
}
```

**Worker Script**:
```javascript
// worker.js
const { workerData, parentPort } = require('worker_threads');

// Heavy computation
function heavyComputation(data) {
  // CPU intensive work here
  return result;
}

const result = heavyComputation(workerData.data);
parentPort.postMessage(result);
```

**Thread Pool**:
```javascript
const { Worker, isMainThread, parentPort, workerData } = require('worker_threads');

if (isMainThread) {
  // Create worker pool
  const workers = [];
  for (let i = 0; i < 4; i++) {
    workers.push(new Worker(__filename));
  }
} else {
  // Worker logic
}
```

**Use Cases**:
- Image processing
- Data compression
- Cryptographic operations
- Mathematical computations

Worker threads enable true parallelism in Node.js!

