**Custom Event Emitter**:
```javascript
class MyEmitter extends EventEmitter {
  constructor() {
    super();
    this.start();
  }

  start() {
    setInterval(() => {
      this.emit('tick', Date.now());
    }, 1000);
  }
}

const emitter = new MyEmitter();
