TLS module provides implementation of TLS/SSL protocols for secure network communication.

**TLS Server**:
```javascript
const tls = require('tls');
const fs = require('fs');

const options = {
  key: fs.readFileSync('server-key.pem'),
  cert: fs.readFileSync('server-cert.pem'),
  ca: fs.readFileSync('ca-cert.pem'), // Optional CA certificate
  requestCert: true, // Request client certificate
  rejectUnauthorized: true // Reject unauthorized clients
};

const server = tls.createServer(options, (socket) => {
  console.log('Secure connection established');

  socket.on('data', (data) => {
    console.log('Received:', data.toString());
    socket.write('Secure response');
  });

  socket.on('end', () => {
    console.log('Client disconnected');
  });
});

server.listen(8443, () => {
  console.log('TLS server listening on port 8443');
});
```

**TLS Client**:
```javascript
const socket = tls.connect(8443, 'localhost', { 
  rejectUnauthorized: false // For testing only
}, () => {
  console.log('Connected to TLS server');
  socket.write('Hello secure server!');
});

socket.on('data', (data) => {
  console.log('Received:', data.toString());
  socket.end();
});

socket.on('error', (err) => {
  console.error('TLS error:', err);
});
```

**Certificate Validation**:
