Stream module provides API for streaming data between sources and destinations in Node.js.

**Stream Types**:
```javascript
const { Readable, Writable, Transform, Duplex } = require('stream');

// Readable stream
class MyReadable extends Readable {
  constructor(options) {
    super(options);
    this.data = ['Hello', 'World', 'Stream'];
    this.index = 0;
  }

  _read(size) {
    if (this.index < this.data.length) {
      this.push(this.data[this.index++]);
    } else {
      this.push(null); // End of stream
    }
  }
}

// Writable stream
class MyWritable extends Writable {
  _write(chunk, encoding, callback) {
    console.log('Writing:', chunk.toString());
    callback();
  }
}
```

**Transform Stream**:
```javascript
class UpperCase extends Transform {
  _transform(chunk, encoding, callback) {
    this.push(chunk.toString().toUpperCase());
    callback();
  }
}
```

**Stream Pipeline**:
```javascript
const { pipeline } = require('stream');
const fs = require('fs');

// Pipe streams together
pipeline(
  fs.createReadStream('input.txt'),
  new UpperCase(),
  fs.createWriteStream('output.txt'),
  (err) => {
    if (err) console.error('Pipeline failed:', err);
    else console.log('Pipeline completed');
  }
);
```

**Stream Events**:
```javascript
const readable = fs.createReadStream('file.txt');

readable.on('data', (chunk) => {
  console.log('Received chunk:', chunk.length);
});

readable.on('end', () => {
  console.log('Stream ended');
});

readable.on('error', (err) => {
  console.error('Stream error:', err);
});
```

**Use Cases**:
- File processing
- Network communication
- Data transformation
- Real-time processing

Stream module enables efficient data flow in Node.js!

