  console.log('Connected to TCP server');
  client.write('Hello, server!');
});

client.on('data', (data) => {
  console.log('Received:', data.toString());
  client.end();
});

client.on('error', (err) => {
  console.error('Client error:', err);
});
```

**Server Options**:
```javascript
const server = net.createServer({
  allowHalfOpen: true, // Allow half-open TCP connections
  pauseOnConnect: false // Don't pause connections on creation
}, (socket) => {
  // Connection handling
});
